"use client"
import * as React from "react"
import { useRouter } from "next/navigation"
import { Button, ContentForm, PageHeader, Panel, Shell, useContentStore } from "./content-command-system"
export default function ContentCreatePage(){
 const router=useRouter(); const {commit}=useContentStore()
 return <Shell><main className="mx-auto max-w-6xl space-y-6 p-4 lg:p-8"><PageHeader eyebrow="Content Command / Create" title="Create a new content production item" description="Register a real content item with owner, channel, campaign link, deadline, content body, CTA, reviewer, and schedule. Saving makes it appear in the main workspace, calendar, review queue, and publishing pages." actions={<Button href="/market-os/content-command-center">Back to command center</Button>} />
 <Panel className="p-6"><ContentForm submitLabel="Save content and return" onSave={(item)=>{commit(d=>{d.items=[item,...d.items]},"create",`Created content ${item.title}`); router.push("/market-os/content-command-center")}} /></Panel></main></Shell>
}

